def solve(cyanobloom_data):
    if not cyanobloom_data:
        return "No data provided"

    # Example processing of the data
    processed_data = []
    for bloom in cyanobloom_data:
        if isinstance(bloom, dict) and 'location' in bloom and 'severity' in bloom:
            processed_data.append((bloom['location'], bloom['severity']))

    if not processed_data:
        return "No valid bloom data found"

    return processed_data
